function solve(n, edges, label) {
    // Build the graph
    const graph = new Array(n).fill().map(() => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    let maxLen = 1;

    // BFS for each node as starting point
    for (let start = 0; start < n; start++) {
        const queue = [];
        const initialMask = 1 << start;
        const initialFreq = new Array(26).fill(0);
        initialFreq[label.charCodeAt(start) - 'a'.charCodeAt(0)]++;
        queue.push([start, initialMask, initialFreq]);

        while (queue.length > 0) {
            const [node, mask, freq] = queue.shift();

            // Check if current frequency can form a palindrome
            let oddCount = 0;
            let total = 0;
            for (const count of freq) {
                total += count;
                if (count % 2 === 1) {
                    oddCount++;
                }
            }
            if (oddCount <= 1) {
                if (total > maxLen) {
                    maxLen = total;
                }
            }

            // Explore neighbors
            for (const neighbor of graph[node]) {
                if (!(mask & (1 << neighbor))) {
                    const newMask = mask | (1 << neighbor);
                    const newFreq = [...freq];
                    newFreq[label.charCodeAt(neighbor) - 'a'.charCodeAt(0)]++;
                    queue.push([neighbor, newMask, newFreq]);
                }
            }
        }
    }

    return maxLen;
}
